const info = $('Info_base').first().json;
const board = info.funil;
const task = info.tarefa;

// Sem task no Kanban? Reset só de memória, pula task move/clear.
if (!task?.id || !board?.steps?.length) {
  return [];
}

// /reset só mexe no funil Assistente Jurídicaa. NUNCA resetar tarefas de Urgências
// (urgência tem lifecycle próprio e ficou ligado à conversa por conversation_ids).
if (String(board.name || '').toLowerCase() === 'urgências') {
  return [];
}

// O payload já vem de ordered_steps — primeiro item = primeiro step do funil.
const firstStep = board.steps[0];

return [{
  json: {
    account_id: info.id_conta,
    task_id: task.id,
    step_id: firstStep.id,
    board_id: board.id,
  }
}];

const https = require('https');
const url = require('url');

const CHATWOOT_HOST = 'app.companychatia.com.br';
const TOKEN = 'S4F3XsApoYv9pxMr6N12QZHd';
const BOARD_ID = 21;
const FIRST_STEP_ID = 120;

function chatwootRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const postData = body ? JSON.stringify(body) : undefined;
    const options = {
      hostname: CHATWOOT_HOST,
      path: path,
      method: method,
      headers: {
        'Api-Access-Token': TOKEN,
        'Content-Type': 'application/json',
        ...(postData ? { 'Content-Length': Buffer.byteLength(postData) } : {})
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { reject(new Error('JSON parse error: ' + data.substring(0, 200))); }
      });
    });
    req.on('error', reject);
    if (postData) req.write(postData);
    req.end();
  });
}

const infoBase = $('Info_base').first().json;

// If webhook payload already has a valid task, pass through
if (infoBase.tarefa && infoBase.tarefa.id) {
  return [{ json: infoBase }];
}

const accountId = infoBase.id_conta;
const contactId = parseInt(infoBase.id_contato);
const nome = infoBase.nome || 'Cliente';

// Check if this contact already has a task in this board (deduplication)
const listData = await chatwootRequest('GET', `/api/v1/accounts/${accountId}/kanban/tasks?board_id=${BOARD_ID}`);
const existing = (listData.tasks || []).find(t => Array.isArray(t.contact_ids) && t.contact_ids.includes(contactId));

let taskId;
if (existing) {
  taskId = existing.id;
} else {
  const created = await chatwootRequest('POST', `/api/v1/accounts/${accountId}/kanban/tasks`, {
    task: { title: 'Trab - ' + nome, board_id: BOARD_ID, board_step_id: FIRST_STEP_ID, contact_ids: [contactId] }
  });
  taskId = created.id;
}

// Fetch full task with board+steps
const fullTask = await chatwootRequest('GET', `/api/v1/accounts/${accountId}/kanban/tasks/${taskId}`);

return [{ json: { ...infoBase, tarefa: fullTask, funil: fullTask.board } }];

